def embed_fn(text):
    vecs = {'cat': np.array([1,0,0]), 'dog': np.array([0,1,0]), 'fish': np.array([0,0,1])}
    return vecs.get(text.lower().split()[0], np.ones(3)/3)
rag = RAGPipeline(embed_fn)
rag.index(['cat is a pet', 'dog is loyal', 'fish swims'])
results = rag.retrieve('cat meows', k=1)
assert 'cat' in results[0][0]

def embed_fn(text): return np.ones(3)
rag = RAGPipeline(embed_fn)
rag.index(['a', 'b', 'c'])
results = rag.retrieve('q', k=3)
for doc, score in results:
    assert -1.01 <= score <= 1.01
